import{c as t,Q as a,j as n,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"The Anatomy of an Agent Harness","description":"","frontmatter":{"title":"The Anatomy of an Agent Harness","date":"2026-04-01T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-01-anatomy-of-agent-harness.md","filePath":"research/ai-articles/scored/2026-04-01-anatomy-of-agent-harness.md","lastUpdated":1779894392000}'),r={name:"research/ai-articles/scored/2026-04-01-anatomy-of-agent-harness.md"};function s(i,e,l,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<blockquote><p>Source: <a href="https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness" target="_blank" rel="noreferrer">https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness</a> Fetched: 2026-05-08</p></blockquote><h1 id="the-anatomy-of-an-agent-harness" tabindex="-1">The Anatomy of an Agent Harness <a class="header-anchor" href="#the-anatomy-of-an-agent-harness" aria-label="Permalink to &quot;The Anatomy of an Agent Harness&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Before foundation models emerged, developing AI features required collecting labeled training data, training custom models, and investing significant compute before validating user demand. Foundation models disrupted this by offering pre-trained capabilities via API, enabling teams to ship MVPs in days rather than months.</p><p>However, agentic systems introduce a new complexity layer. Agent design must follow product definition because &quot;the agent&#39;s capabilities, workflows, and memory requirements are what determine what knowledge it needs and which model providers make sense downstream.&quot;</p><h2 id="the-canvas-framework" tabindex="-1">The Canvas Framework <a class="header-anchor" href="#the-canvas-framework" aria-label="Permalink to &quot;The Canvas Framework&quot;">​</a></h2><p>MongoDB published the Canvas Framework, which structures agent development in two phases:</p><p><strong>POC Canvas</strong> covers eight areas: product validation, agent design (capabilities, autonomy, memory), data requirements (knowledge sources, update frequency), and model integration (provider selection, prompt strategy, cost).</p><p><strong>Production Canvas</strong> adds eleven elements for scaling: fault tolerance, multi-agent coordination, unified data architecture, security hardening, and governance.</p><h2 id="what-is-an-agent-harness" tabindex="-1">What Is an Agent Harness? <a class="header-anchor" href="#what-is-an-agent-harness" aria-label="Permalink to &quot;What Is an Agent Harness?&quot;">​</a></h2><p>An agent harness represents &quot;the complete software infrastructure wrapping an LLM, including the orchestration loop, tools, memory, context management, state persistence, error handling, and guardrails.&quot;</p><p>The distinction matters: the agent itself is emergent behavior—the goal-directed, tool-using entity users interact with. The harness is the machinery producing that behavior.</p><p>Using Beren Millidge&#39;s analogy, a raw LLM functions like a CPU without RAM, disk, or I/O:</p><ul><li>Context window = RAM (fast, limited)</li><li>External databases = disk storage (large, slow)</li><li>Tool integrations = device drivers</li><li>The harness = operating system</li></ul><h2 id="three-levels-of-engineering" tabindex="-1">Three Levels of Engineering <a class="header-anchor" href="#three-levels-of-engineering" aria-label="Permalink to &quot;Three Levels of Engineering&quot;">​</a></h2><p><strong>Prompt engineering</strong> crafts model instructions. <strong>Context engineering</strong> manages what models see and when. <strong>Harness engineering</strong> encompasses both plus complete application infrastructure: tool orchestration, state persistence, error recovery, verification loops, safety enforcement, and lifecycle management.</p><h2 id="the-11-components-of-a-production-harness" tabindex="-1">The 11 Components of a Production Harness <a class="header-anchor" href="#the-11-components-of-a-production-harness" aria-label="Permalink to &quot;The 11 Components of a Production Harness&quot;">​</a></h2><h3 id="_1-the-orchestration-loop" tabindex="-1">1. The Orchestration Loop <a class="header-anchor" href="#_1-the-orchestration-loop" aria-label="Permalink to &quot;1. The Orchestration Loop&quot;">​</a></h3><p>This implements the Thought-Action-Observation cycle, repeating: assemble prompt, call LLM, parse output, execute tool calls, feed results back. Anthropic describes this as a &quot;dumb loop&quot; where intelligence resides in the model, not the orchestration mechanism.</p><h3 id="_2-tools" tabindex="-1">2. Tools <a class="header-anchor" href="#_2-tools" aria-label="Permalink to &quot;2. Tools&quot;">​</a></h3><p>Tools function as the agent&#39;s interface to external systems. They&#39;re defined as schemas injected into the LLM&#39;s context. The tool layer manages registration, schema validation, argument extraction, sandboxed execution, result capture, and formatting. Claude Code provides tools across six categories: file operations, search, execution, web access, code intelligence, and subagent spawning.</p><h3 id="_3-memory" tabindex="-1">3. Memory <a class="header-anchor" href="#_3-memory" aria-label="Permalink to &quot;3. Memory&quot;">​</a></h3><p>Memory operates across multiple timescales. Short-term memory comprises conversation history within sessions. Long-term memory persists across sessions—Anthropic uses project files and auto-generated memory files; LangGraph uses namespace-organized JSON stores.</p><p>Claude Code implements a three-tier hierarchy: lightweight indexes (~150 characters per entry, always loaded), detailed topic files loaded on demand, and raw transcripts accessed via search only.</p><h3 id="_4-context-management" tabindex="-1">4. Context Management <a class="header-anchor" href="#_4-context-management" aria-label="Permalink to &quot;4. Context Management&quot;">​</a></h3><p>Context rot represents a critical challenge: &quot;model performance degrades 30%+ when key content falls in mid-window positions.&quot; Production strategies include:</p><ul><li><strong>Compaction</strong>: summarizing conversation history while preserving architectural decisions and unresolved issues</li><li><strong>Observation masking</strong>: hiding old tool outputs while keeping tool calls visible</li><li><strong>Just-in-time retrieval</strong>: maintaining lightweight identifiers and loading data dynamically</li><li><strong>Sub-agent delegation</strong>: returning condensed 1,000-2,000 token summaries rather than full context</li></ul><h3 id="_5-prompt-construction" tabindex="-1">5. Prompt Construction <a class="header-anchor" href="#_5-prompt-construction" aria-label="Permalink to &quot;5. Prompt Construction&quot;">​</a></h3><p>This assembles what the model receives at each step—system prompt, tool definitions, memory files, conversation history, and current user message. OpenAI&#39;s Codex uses a strict priority stack with server-controlled system messages at highest priority, followed by tool definitions, developer instructions, and user instructions.</p><h3 id="_6-output-parsing" tabindex="-1">6. Output Parsing <a class="header-anchor" href="#_6-output-parsing" aria-label="Permalink to &quot;6. Output Parsing&quot;">​</a></h3><p>Modern harnesses rely on native tool calling, where models return structured <code>tool_calls</code> objects rather than free-text requiring parsing. The harness checks for tool calls, executes them if present, and loops accordingly.</p><h3 id="_7-state-management" tabindex="-1">7. State Management <a class="header-anchor" href="#_7-state-management" aria-label="Permalink to &quot;7. State Management&quot;">​</a></h3><p>LangGraph models state as typed dictionaries flowing through graph nodes. Checkpointing occurs at super-step boundaries, enabling resumption after interruptions. OpenAI offers four mutually exclusive strategies: application memory, SDK sessions, server-side Conversations API, or lightweight response chaining.</p><h3 id="_8-error-handling" tabindex="-1">8. Error Handling <a class="header-anchor" href="#_8-error-handling" aria-label="Permalink to &quot;8. Error Handling&quot;">​</a></h3><p>A 10-step process with 99% per-step success still achieves only ~90.4% end-to-end success due to compounding failures. LangGraph distinguishes four error types: transient (retry with backoff), LLM-recoverable (return error as ToolMessage), user-fixable (interrupt for input), and unexpected (bubble up for debugging).</p><h3 id="_9-guardrails-and-safety" tabindex="-1">9. Guardrails and Safety <a class="header-anchor" href="#_9-guardrails-and-safety" aria-label="Permalink to &quot;9. Guardrails and Safety&quot;">​</a></h3><p>OpenAI&#39;s SDK implements three levels: input guardrails (on first agent), output guardrails (on final output), and tool guardrails (on every invocation). Anthropic separates permission enforcement from model reasoning—the model decides what to attempt; the tool system decides what&#39;s allowed. Claude Code gates approximately 40 discrete tool capabilities independently with three stages: trust establishment, permission checking, and user confirmation for high-risk operations.</p><h3 id="_10-verification-loops" tabindex="-1">10. Verification Loops <a class="header-anchor" href="#_10-verification-loops" aria-label="Permalink to &quot;10. Verification Loops&quot;">​</a></h3><p>This separates production agents from demos. Recommended approaches include rules-based feedback (tests, linters), visual feedback (screenshots), and LLM-as-judge (separate subagent evaluation). &quot;Giving the model a way to verify its work improves quality by 2 to 3x.&quot;</p><h3 id="_11-subagent-orchestration" tabindex="-1">11. Subagent Orchestration <a class="header-anchor" href="#_11-subagent-orchestration" aria-label="Permalink to &quot;11. Subagent Orchestration&quot;">​</a></h3><p>Claude Code supports three execution models: Fork (byte-identical context copy), Teammate (separate terminal with file-based communication), and Worktree (own git worktree). OpenAI supports agents-as-tools (specialist handling bounded subtasks) and handoffs (specialist taking full control).</p><h2 id="step-by-step-walkthrough" tabindex="-1">Step-by-Step Walkthrough <a class="header-anchor" href="#step-by-step-walkthrough" aria-label="Permalink to &quot;Step-by-Step Walkthrough&quot;">​</a></h2><p><strong>Step 1 (Prompt Assembly)</strong>: Construct full input combining system prompt, tool schemas, memory files, conversation history, and current message. Important context positions at beginning and end.</p><p><strong>Step 2 (LLM Inference)</strong>: Send assembled prompt to model API. Model generates text, tool calls, or both.</p><p><strong>Step 3 (Output Classification)</strong>: If text without tool calls, terminate loop. If tool calls requested, proceed to execution. If handoff requested, update current agent and restart.</p><p><strong>Step 4 (Tool Execution)</strong>: Validate arguments, check permissions, execute in sandboxed environment, capture results. Read-only operations run concurrently; mutating operations run serially.</p><p><strong>Step 5 (Result Packaging)</strong>: Format results as LLM-readable messages. Return errors as error results enabling model self-correction.</p><p><strong>Step 6 (Context Update)</strong>: Append results to conversation history. If approaching context limits, trigger compaction.</p><p><strong>Step 7 (Loop)</strong>: Return to Step 1 until termination conditions met.</p><p>Termination occurs when the model produces responses without tool calls, maximum turn limits exceeded, token budgets exhausted, guardrails trigger, users interrupt, or safety refusals occur.</p><p>For long-running tasks spanning multiple context windows, Anthropic developed the &quot;Ralph Loop&quot; pattern: an Initializer Agent sets up environments, then a Coding Agent in subsequent sessions reads git logs and progress files to orient itself, selecting highest-priority incomplete features.</p><h2 id="framework-implementations" tabindex="-1">Framework Implementations <a class="header-anchor" href="#framework-implementations" aria-label="Permalink to &quot;Framework Implementations&quot;">​</a></h2><p><strong>Anthropic&#39;s Claude Agent SDK</strong> exposes the harness through a single <code>query()</code> function creating the agentic loop and returning an async iterator. The runtime is a &quot;dumb loop&quot; where all intelligence lives in the model. Claude Code uses a Gather-Act-Verify cycle: gather context, take action, verify results.</p><p><strong>OpenAI&#39;s Agents SDK</strong> implements the harness through the Runner class with three modes: async, sync, and streamed. It&#39;s &quot;code-first,&quot; expressing workflow logic in native Python rather than graph DSLs.</p><p><strong>LangGraph</strong> models the harness as explicit state graphs with two nodes (<code>llm_call</code> and <code>tool_node</code>) connected by conditional edges. It evolved from LangChain&#39;s deprecated AgentExecutor, which lacked multi-agent support and extensibility.</p><p><strong>LangChain&#39;s Deep Agents</strong> explicitly use &quot;agent harness&quot; terminology: built-in tools, planning, file systems for context management, subagent spawning, and persistent memory.</p><p><strong>CrewAI</strong> implements role-based multi-agent architecture: Agent (harness around LLM defined by role, goal, backstory, tools), Task (unit of work), and Crew (agent collection). Its Flows layer adds &quot;deterministic backbone with intelligence where it matters.&quot;</p><h2 id="the-scaffolding-metaphor" tabindex="-1">The Scaffolding Metaphor <a class="header-anchor" href="#the-scaffolding-metaphor" aria-label="Permalink to &quot;The Scaffolding Metaphor&quot;">​</a></h2><p>Construction scaffolding enables workers to build structures they couldn&#39;t reach otherwise. It doesn&#39;t perform construction but enables workers to access upper floors.</p><p>As models improve, harness complexity should decrease. Manus was rebuilt five times in six months, each rewrite removing complexity. Complex tool definitions became general shell execution; &quot;management agents&quot; became simple structured handoffs.</p><p>This reveals the co-evolution principle: models now post-train with specific harnesses in the loop. Claude Code&#39;s model learned to use its specific harness. Changing tool implementations can degrade performance due to tight coupling.</p><p>The future-proofing test states: &quot;if performance scales up with more powerful models without adding harness complexity, the design is sound.&quot;</p><h2 id="seven-harness-architecture-decisions" tabindex="-1">Seven Harness Architecture Decisions <a class="header-anchor" href="#seven-harness-architecture-decisions" aria-label="Permalink to &quot;Seven Harness Architecture Decisions&quot;">​</a></h2><p>Every harness architect faces seven key choices:</p><p><strong>1. Single-agent vs. multi-agent</strong>: Both Anthropic and OpenAI recommend maximizing single agents first. Multi-agent systems add overhead through extra LLM calls for routing and context loss during handoffs. Split when tool overload exceeds approximately 10 overlapping tools or clearly separate task domains exist.</p><p><strong>2. ReAct vs. plan-and-execute</strong>: ReAct interleaves reasoning and action at every step (flexible but higher per-step cost). Plan-and-execute separates planning from execution. LLMCompiler reports 3.6x speedup over sequential ReAct.</p><p><strong>3. Context window management strategy</strong>: Five production approaches include time-based clearing, conversation summarization, observation masking, structured note-taking, and sub-agent delegation. ACON research showed 26-54% token reduction while preserving 95%+ accuracy.</p><p><strong>4. Verification loop design</strong>: Computational verification (tests, linters) provides deterministic ground truth. Inferential verification (LLM-as-judge) catches semantic issues but adds latency.</p><p><strong>5. Permission and safety architecture</strong>: Permissive approaches (fast, risky) versus restrictive approaches (safe, slow) depend on deployment context.</p><p><strong>6. Tool scoping strategy</strong>: More tools often mean worse performance. Vercel removed 80% of tools from v0 and achieved better results. Claude Code achieves 95% context reduction via lazy loading. The principle: expose the minimum tool set needed for the current step.</p><p><strong>7. Harness thickness</strong>: How much logic lives in the harness versus the model. Anthropic bets on thin harnesses and model improvement. Graph-based frameworks bet on explicit control. Anthropic regularly deletes planning steps from Claude Code as new model versions internalize that capability.</p><h2 id="the-harness-is-the-product" tabindex="-1">The Harness Is the Product <a class="header-anchor" href="#the-harness-is-the-product" aria-label="Permalink to &quot;The Harness Is the Product&quot;">​</a></h2><p>Two products using identical models can have wildly different performance based solely on harness design. TerminalBench evidence demonstrates that changing only the harness moved agents by 20+ ranking positions. One research project achieved 76.4% pass rates by having an LLM optimize the infrastructure itself, surpassing hand-designed systems. LangChain changed only infrastructure wrapping their LLM (same model, same weights) and jumped from outside the top 30 to rank 5 on TerminalBench 2.0.</p><p>The harness represents a non-commoditized layer where hard engineering lives: managing context as scarce resource, designing verification loops catching failures before compounding, building memory systems providing continuity without hallucination, and making architectural bets about scaffolding versus model capability.</p><p>The field moves toward thinner harnesses as models improve. But harnesses themselves won&#39;t disappear. &quot;Even the most capable model needs something to manage its context window, execute its tool calls, persist its state, and verify its work.&quot;</p><p>The key insight: &quot;The next time your agent fails, don&#39;t blame the model but rather look at the harness.&quot;</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題-harness-就是產品" tabindex="-1">核心命題：Harness 就是產品 <a class="header-anchor" href="#核心命題-harness-就是產品" aria-label="Permalink to &quot;核心命題：Harness 就是產品&quot;">​</a></h3><p>兩個使用相同模型的產品，僅憑 harness 設計就能有天壤之別的效能。TerminalBench 2.0 實證：僅改變 harness，LangChain DeepAgent 從第 30 名外躍升至第 5 名；同一模型。<strong>下次 Agent 失敗，不要怪模型，看 harness</strong>。</p><h3 id="canvas-framework-poc-→-production-雙階段" tabindex="-1">Canvas Framework：POC → Production 雙階段 <a class="header-anchor" href="#canvas-framework-poc-→-production-雙階段" aria-label="Permalink to &quot;Canvas Framework：POC → Production 雙階段&quot;">​</a></h3><p><strong>POC Canvas（概念驗證）</strong>：8 個領域——產品驗證、Agent 設計（能力、自主性、記憶）、資料需求、模型整合</p><p><strong>Production Canvas</strong>：再增加 11 個要素——容錯、多代理協調、統一資料架構、安全加固、治理</p><h3 id="生產-harness-的-11-大組件" tabindex="-1">生產 Harness 的 11 大組件 <a class="header-anchor" href="#生產-harness-的-11-大組件" aria-label="Permalink to &quot;生產 Harness 的 11 大組件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>組件</th><th>職責</th><th>關鍵細節</th></tr></thead><tbody><tr><td><strong>1. Orchestration Loop</strong></td><td>Thought-Action-Observation 循環</td><td>「笨循環」—智能在模型，不在循環機制</td></tr><tr><td><strong>2. Tools</strong></td><td>Agent 與外部系統的介面</td><td>Schema 注入 context；6 類工具（檔案、搜尋、執行、網路、程式智能、子代理）</td></tr><tr><td><strong>3. Memory</strong></td><td>多時間尺度記憶</td><td>短期（session 內）+ 長期（跨 session）；三層層級</td></tr><tr><td><strong>4. Context Management</strong></td><td>管理 context rot</td><td>壓縮、觀察遮罩、即時載入、子代理委派</td></tr><tr><td><strong>5. Prompt Construction</strong></td><td>組裝模型輸入</td><td>系統提示 + 工具定義 + 記憶檔 + 對話歷史 + 當前訊息</td></tr><tr><td><strong>6. Output Parsing</strong></td><td>解析模型輸出</td><td>原生工具呼叫（<code>tool_calls</code> 物件）&gt; 自由文字解析</td></tr><tr><td><strong>7. State Management</strong></td><td>管理執行狀態</td><td>LangGraph 型別字典 + checkpoint；四種互斥策略</td></tr><tr><td><strong>8. Error Handling</strong></td><td>處理失敗</td><td>四類錯誤：瞬時/LLM 可恢復/需用戶介入/意外</td></tr><tr><td><strong>9. Guardrails &amp; Safety</strong></td><td>安全護欄</td><td>輸入/輸出/工具三層；模型決定嘗試，工具系統決定是否允許</td></tr><tr><td><strong>10. Verification Loops</strong></td><td>驗證輸出</td><td>規則型（測試、linter）+ 視覺 + LLM-as-judge；驗證改進品質 2-3x</td></tr><tr><td><strong>11. Subagent Orchestration</strong></td><td>子代理協調</td><td>Fork / Teammate / Worktree 三種執行模式</td></tr></tbody></table><h3 id="關鍵量化數據" tabindex="-1">關鍵量化數據 <a class="header-anchor" href="#關鍵量化數據" aria-label="Permalink to &quot;關鍵量化數據&quot;">​</a></h3><ul><li><strong>Context rot</strong>：關鍵內容落在 context 中間時，模型效能下降 <strong>30%+</strong></li><li><strong>ACON 壓縮</strong>：26-54% token 減少，同時保留 <strong>95%+</strong> 精準度</li><li><strong>Verification 效果</strong>：讓模型有方法驗證自己的工作，品質提升 <strong>2-3x</strong></li><li><strong>Tool 精簡</strong>：Vercel 移除 80% 工具後結果更好；Claude Code 懶載入實現 <strong>95%</strong> context 減少</li></ul><h3 id="七大架構決策" tabindex="-1">七大架構決策 <a class="header-anchor" href="#七大架構決策" aria-label="Permalink to &quot;七大架構決策&quot;">​</a></h3><ol><li><strong>單代理 vs. 多代理</strong>：優先最大化單代理；工具超過 ~10 個重疊或任務域清楚分離時才分割</li><li><strong>ReAct vs. 計劃-執行分離</strong>：LLMCompiler 報告比循序 ReAct 快 3.6x</li><li><strong>Context Window 管理策略</strong>：5 種生產方法（時間清除、對話摘要、觀察遮罩、結構化筆記、子代理委派）</li><li><strong>驗證循環設計</strong>：計算驗證（確定性）vs. 推理驗證（LLM-as-judge，語義更佳但延遲更高）</li><li><strong>權限與安全架構</strong>：寬鬆（快但風險）vs. 限制（安全但慢）</li><li><strong>工具範圍策略</strong>：最少工具原則——只暴露當前步驟所需的最小工具集</li><li><strong>Harness 厚度</strong>：Anthropic 押注薄 harness + 模型改進；圖形框架押注明確控制</li></ol><h3 id="co-evolution-原則" tabindex="-1">Co-Evolution 原則 <a class="header-anchor" href="#co-evolution-原則" aria-label="Permalink to &quot;Co-Evolution 原則&quot;">​</a></h3><p>模型現在與特定 harness 一起後訓練——Claude Code 的模型學習使用其特定 harness。改變工具實作可能因緊耦合而降低效能。<strong>未來驗證測試</strong>：「如果更強大的模型帶來效能提升且不增加 harness 複雜性，設計就是健全的。」</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>Canvas Framework（POC vs Production）、7 個架構決策均可直接套用</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>Canvas Framework 原創、ACON 壓縮指標、Co-Evolution 原則新穎</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>context rot -30%、ACON 26-54% 壓縮、驗證 2-3x 品質提升有量化數據</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>11 個組件詳細說明、7 個架構決策、Context Manager 機制</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>Canvas Framework 適用任何規模的 harness 設計</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.3/10</strong></td><td>9×0.3+8×0.2+8×0.2+8×0.15+8×0.15 = 2.7+1.6+1.6+1.2+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：SKILL<br><strong>整合位置</strong>：<code>.claude/skills/harness-eval/</code>（Canvas Framework 作為評估工具）<br><strong>整合狀態</strong>：待實作</p>',95)])])}const u=t(r,[["render",s]]);export{g as __pageData,u as default};
